# 2. 绘制收盘价曲线图
# 设置中文字体
font_paths = fm.findSystemFonts(fontpaths=None, fontext='ttf')
cn_font = None
for fp in font_paths:
    if any(k in fp for k in ['msyh', 'simhei', 'simsun', 'Microsoft YaHei', 'SimHei', 'pingfang', 'NotoSansCJK', 'SourceHan']):
        cn_font = fp
        break

if cn_font:
    prop = fm.FontProperties(fname=cn_font)
else:
    prop = fm.FontProperties()

plt.rcParams['axes.unicode_minus'] = False
if cn_font:
    plt.rcParams['font.family'] = fm.FontProperties(fname=cn_font).get_name()

fig, ax = plt.subplots(figsize=(14, 6))
dates = [datetime.strptime(r['trade_date'], '%Y%m%d') for r in raw_data]
closes = [r['close'] for r in raw_data]

ax.plot(dates, closes, color='#E03030', linewidth=1.5)
ax.set_title('芯动联科 (688582.SH) 每日收盘价走势图 (2025-07-04 ~ 2026-07-03)', fontsize=14, fontproperties=prop)
ax.set_xlabel('交易日期', fontsize=11, fontproperties=prop)
ax.set_ylabel('收盘价 (元)', fontsize=11, fontproperties=prop)
ax.grid(True, linestyle='--', alpha=0.4)
fig.autofmt_xdate()

# 标注最高价和最低价
max_close = max(closes)
min_close = min(closes)
max_idx = closes.index(max_close)
min_idx = closes.index(min_close)
ax.annotate(f'最高 {max_close}', xy=(dates[max_idx], max_close), xytext=(10, 10),
            textcoords='offset points', fontproperties=prop, fontsize=9,
            arrowprops=dict(arrowstyle='->', color='red'))
ax.annotate(f'最低 {min_close}', xy=(dates[min_idx], min_close), xytext=(10, -20),
            textcoords='offset points', fontproperties=prop, fontsize=9,
            arrowprops=dict(arrowstyle='->', color='green'))

